140→export async function createObservation(
141→  surreal: Surreal,
142→  workspaceId: string,
143→  options: {
144→    text: string;
145→    severity: ObservationSeverity;
146→    sourceAgent: string;
147→    category?: string;
148→    embedding?: number[];
149→    targetEntity?: { table: string; id: string };
