516→// ---------------------------------------------------------------------------
517→// Feed Stream Helpers
518→// ---------------------------------------------------------------------------
519→
520→/**
521→ * Opens an SSE connection to the governance feed stream for a workspace.
522→ * Returns a controller that can collect events and close the connection.
523→ */
524→export function openFeedStream(
525→  baseUrl: string,
526→  workspaceId: string,
527→  user: TestUser,
528→  options?: { lastEventId?: string },
529→): FeedStreamController {
530→  return new FeedStreamController(baseUrl, workspaceId, user, options);
531→}
532→
533→export class FeedStreamController {
534→  private events: FeedStreamEvent[] = [];
535→  private rawEvents: string[] = [];
536→  private reader: ReadableStreamDefaultReader<Uint8Array> | undefined;
537→  private abortController = new AbortController();
538→  private buffer = "";
539→  private decoder = new TextDecoder();
540→  private connected = false;
541→  private connectionPromise: Promise<void> | undefined;
542→  private lastEventId: string | undefined;
543→
544→  constructor(
545→    private baseUrl: string,
546→    private workspaceId: string,
547→    private user: TestUser,
548→    private options?: { lastEventId?: string },
549→  ) {
550→    this.lastEventId = options?.lastEventId;
551→  }
552→
553→  /** Start listening for SSE events. */
554→  async connect(): Promise<void> {
555→    this.connectionPromise = this._connect();
556→    // Give the connection a moment to establish
557→    await new Promise((resolve) => setTimeout(resolve, 200));
558→  }
559→
560→  /** Get the last event ID received from the server. */
561→  getLastEventId(): string | undefined {
562→    return this.lastEventId;
563→  }
564→
565→  private async _connect(): Promise<void> {
566→    const url = `${this.baseUrl}/api/workspaces/${this.workspaceId}/feed/stream`;
567→    const headers: Record<string, string> = {
568→      Accept: "text/event-stream",
569→      ...this.user.headers,
570→    };
571→    if (this.lastEventId) {
572→      headers["Last-Event-ID"] = this.lastEventId;
573→    }
574→    const response = await fetch(url, {
575→      headers,
576→      signal: this.abortController.signal,
577→    });
578→
579→    if (!response.ok || !response.body) {
580→      throw new Error(`Failed to open feed stream (${response.status})`);
581→    }
582→
583→    this.connected = true;
584→    this.reader = response.body.getReader();
585→
586→    try {
587→      while (true) {
588→        const { value, done } = await this.reader.read();
589→        if (done) break;
590→
591→        this.buffer += this.decoder.decode(value, { stream: true });
592→        const segments = this.buffer.split("\n\n");
593→        this.buffer = segments.pop() ?? "";
594→
595→        for (const segment of segments) {
596→          const lines = segment.split("\n");
597→          const idLine = lines.find((line) => line.startsWith("id: "));
598→          const dataLine = lines.find((line) => line.startsWith("data: "));
599→          if (!dataLine) continue;
600→
601→          // Track the last event ID for reconnection
602→          if (idLine) {
603→            this.lastEventId = idLine.slice("id: ".length).trim();
604→          }
605→
606→          const raw = dataLine.slice("data: ".length);
607→          this.rawEvents.push(raw);
608→
609→          try {
610→            const event = JSON.parse(raw) as FeedStreamEvent;
611→            this.events.push(event);
612→          } catch {
613→            // Non-JSON event (keep-alive comment, etc.)
614→          }
615→        }
616→      }
617→    } catch (e: unknown) {
618→      // AbortError is expected when we close the stream
619→      if (e instanceof DOMException && e.name === "AbortError") return;
620→      if (e instanceof Error && e.message.includes("abort")) return;
621→      throw e;
622→    }
623→  }
624→
625→  /** Wait for at least N feed_update events, with timeout. */
626→  async waitForEvents(count: number, timeoutMs: number = 5000): Promise<FeedStreamEvent[]> {
627→    const start = Date.now();
628→    while (this.events.length < count && Date.now() - start < timeoutMs) {
629→      await new Promise((resolve) => setTimeout(resolve, 100));
630→    }
631→    return [...this.events];
632→  }
633→
634→  /** Get all collected events so far. */
635→  getEvents(): FeedStreamEvent[] {
636→    return [...this.events];
637→  }
638→
639→  /** Get all raw event strings. */
640→  getRawEvents(): string[] {
641→    return [...this.rawEvents];
642→  }
643→
644→  /** Whether the stream connection was established. */
645→  isConnected(): boolean {
646→    return this.connected;
647→  }
648→
649→  /** Close the SSE connection. */
650→  close(): void {
651→    this.abortController.abort();
652→    this.connected = false;
653→  }
654→}
655→
656→// ---------------------------------------------------------------------------
657→// Embedding Helpers
658→// ---------------------------------------------------------------------------
659→
660→/**
661→ * Generates real embedding vectors using the configured embedding model.
662→ */
663→export async function generateEmbeddings(
664→  texts: string[],
665→): Promise<Map<string, number[]>> {
666→  const { embeddings } = await embedMany({
667→    model: testAI.embeddingModel,
668→    values: texts,
669→  });
670→  const result = new Map<string, number[]>();
671→  for (let i = 0; i < texts.length; i++) {
672→    result.set(texts[i], embeddings[i]);
673→  }
674→  return result;
675→}
676→
677→/**
678→ * Generates a real embedding vector for a single text.
679→ */
680→export async function generateEmbedding(text: string): Promise<number[]> {
681→  const map = await generateEmbeddings([text]);
682→  return map.get(text)!;
683→}
684→
685→/**
686→ * Creates a deterministic fake embedding vector for testing.
687→ * Uses a seed to produce a reproducible 1536-dimension unit vector.
688→ */
689→export function fakeEmbedding(seed: number): number[] {
690→  const dimension = 1536;
691→  const embedding = new Array<number>(dimension);
692→  let state = seed;
693→  for (let i = 0; i < dimension; i++) {
694→    state = ((state * 1103515245 + 12345) & 0x7fffffff);
695→    embedding[i] = (state / 0x7fffffff) * 2 - 1;
696→  }
697→  const magnitude = Math.sqrt(embedding.reduce((sum, v) => sum + v * v, 0));
698→  for (let i = 0; i < dimension; i++) {
699→    embedding[i] = embedding[i] / magnitude;
700→  }
701→  return embedding;
702→}
703→
704→// ---------------------------------------------------------------------------
705→// Verification Helpers
706→// ---------------------------------------------------------------------------
707→
708→/**
709→ * Queries observations for a workspace.
710→ */
711→export async function getObservations(
712→  surreal: Surreal,
713→  workspaceId: string,
714→  options?: { status?: ObservationStatus; category?: string },
715→): Promise<Array<{ id: RecordId; text: string; severity: string; status: string; category?: string }>> {
716→  const workspaceRecord = new RecordId("workspace", workspaceId);
717→  let query = `SELECT id, text, severity, status, category, created_at FROM observation WHERE workspace = $ws`;
718→  const params: Record<string, unknown> = { ws: workspaceRecord };
719→
720→  if (options?.status) {
721→    query += ` AND status = $status`;
722→    params.status = options.status;
723→  }
724→  if (options?.category) {
725→    query += ` AND category = $category`;
726→    params.category = options.category;
727→  }
728→
729→  query += ` ORDER BY created_at DESC;`;
730→
731→  const rows = (await surreal.query(query, params)) as Array<
732→    Array<{ id: RecordId; text: string; severity: string; status: string; category?: string }>
733→  >;
734→  return rows[0] ?? [];
735→}
736→
737→/**
738→ * Queries provisional decisions created by the agent activator.
739→ */
740→export async function getActivationDecisions(
741→  surreal: Surreal,
742→  workspaceId: string,
743→): Promise<Array<{ id: RecordId; summary: string; rationale: string; status: string; category?: string }>> {
744→  const workspaceRecord = new RecordId("workspace", workspaceId);
745→  const rows = (await surreal.query(
746→    `SELECT id, summary, rationale, status, category, created_at FROM decision
747→     WHERE workspace = $ws AND category = "operations" AND inferred_by = "agent_activator"
748→     ORDER BY created_at DESC;`,
749→    { ws: workspaceRecord },
750→  )) as Array<
751→    Array<{ id: RecordId; summary: string; rationale: string; status: string; category?: string }>
752→  >;
753→  return rows[0] ?? [];
754→}
755→
756→/**
757→ * Gets the current feed state via the existing GET endpoint.
758→ */
759→export async function getFeedState(
760→  baseUrl: string,
761→  workspaceId: string,
762→  user: TestUser,
763→): Promise<Record<string, unknown>> {
764→  const response = await fetchRaw(
765→    `${baseUrl}/api/workspaces/${workspaceId}/feed`,
766→    { headers: user.headers },
767→  );
768→  if (!response.ok) {
769→    throw new Error(`Failed to get feed state (${response.status})`);
770→  }
771→  return (await response.json()) as Record<string, unknown>;
772→}
773→
774→/**
775→ * Checks whether the agent session has a last_request_at timestamp.
776→ */
777→export async function getSessionLastRequestAt(
778→  surreal: Surreal,
779→  sessionId: string,
780→): Promise<string | undefined> {
781→  const sessionRecord = new RecordId("agent_session", sessionId);
782→  const rows = (await surreal.query(
783→    `SELECT last_request_at FROM $sess;`,
784→    { sess: sessionRecord },
785→  )) as Array<Array<{ last_request_at?: string }>>;
786→  return rows[0]?.[0]?.last_request_at;
787→}
788→
789→/**
790→ * Queries agent sessions created by the activator (orchestrator_status = "spawning").
791→ * These are sessions started by the agent activator when LLM classification
792→ * matched an agent type to an observation.
793→ */
794→export async function getActivatedSessions(
795→  surreal: Surreal,
796→  workspaceId: string,
797→): Promise<Array<{ id: RecordId; agent: string; orchestrator_status: string; triggered_by?: RecordId }>> {
798→  const workspaceRecord = new RecordId("workspace", workspaceId);
799→  const rows = (await surreal.query(
800→    `SELECT id, agent, orchestrator_status, triggered_by, created_at FROM agent_session
801→     WHERE workspace = $ws AND source = "activator"
802→     ORDER BY created_at DESC;`,
803→    { ws: workspaceRecord },
804→  )) as Array<
805→    Array<{ id: RecordId; agent: string; orchestrator_status: string; triggered_by?: RecordId }>
806→  >;
