  1→/**
  2→ * Live Select Manager
  3→ *
  4→ * Subscribes to governance tables via LIVE SELECT on the existing surreal
  5→ * WebSocket connection. Routes events to per-workspace consumers after
  6→ * application-side workspace filtering.
  7→ *
  8→ * SurrealDB v3.0 constraint: LIVE SELECT WHERE clauses do not support
  9→ * bound parameters, so workspace filtering happens application-side.
 10→ *
 11→ * Excluded tables (too high volume): trace, message, extracted_from
 12→ */
 13→import { Table, RecordId, type Surreal, type LiveSubscription } from "surrealdb";
 14→
 15→// ---------------------------------------------------------------------------
 16→// Domain Types
 17→// ---------------------------------------------------------------------------
 18→
 19→/** Tables subscribed to via LIVE SELECT. */
 20→export const GOVERNANCE_TABLES = [
 21→  "decision",
 22→  "task",
 23→  "observation",
 24→  "question",
 25→  "suggestion",
 26→  "learning",
 27→  "agent_session",
 28→] as const;
 29→
 30→export type GovernanceTable = (typeof GOVERNANCE_TABLES)[number];
 31→
 32→/** A normalized event from a LIVE SELECT subscription. */
 33→export type LiveSelectEvent = {
 34→  table: string;
 35→  action: "CREATE" | "UPDATE" | "DELETE";
 36→  recordId: string;
 37→  value: Record<string, unknown>;
 38→};
 39→
 40→export type EventConsumer = (event: LiveSelectEvent) => void;
 41→
 42→/** Minimal logger interface for observability. */
 43→export type LiveSelectLogger = {
 44→  info: (message: string) => void;
 45→  warn: (message: string) => void;
 46→  error: (message: string) => void;
 47→};
 48→
 49→// ---------------------------------------------------------------------------
 50→// Pure Functions
 51→// ---------------------------------------------------------------------------
 52→
 53→/**
 54→ * Checks whether a LIVE SELECT event value belongs to the given workspace.
 55→ *
 56→ * The workspace field can be a RecordId object or a string like "workspace:ws-123".
 57→ * Returns false for missing/null/undefined values.
 58→ */
 59→export function matchesWorkspace(
 60→  value: Record<string, unknown> | undefined | null,
 61→  workspaceId: string,
 62→): boolean {
 63→  if (!value) return false;
 64→
 65→  const workspace = value.workspace;
 66→  if (!workspace) return false;
 67→
 68→  // RecordId object (SDK v2)
 69→  if (workspace instanceof RecordId) {
 70→    return (workspace.id as string) === workspaceId;
 71→  }
 72→
 73→  // String format "workspace:ws-123"
 74→  if (typeof workspace === "string") {
 75→    const parts = workspace.split(":");
 76→    if (parts.length >= 2) {
 77→      return parts.slice(1).join(":") === workspaceId;
 78→    }
 79→  }
 80→
 81→  return false;
 82→}
 83→
 84→/**
 85→ * Extracts a string record ID from a RecordId or returns the string as-is.
 86→ */
 87→function extractRecordIdString(recordId: unknown): string {
 88→  if (recordId instanceof RecordId) {
 89→    return `${recordId.table.name}:${recordId.id as string}`;
 90→  }
 91→  return String(recordId);
 92→}
 93→
 94→// ---------------------------------------------------------------------------
 95→// Event Router
 96→// ---------------------------------------------------------------------------
 97→
 98→export type EventRouter = {
 99→  addConsumer: (workspaceId: string, consumer: EventConsumer) => () => void;
100→  addGlobalConsumer: (consumer: EventConsumer) => () => void;
101→  route: (event: LiveSelectEvent) => void;
102→};
103→
104→/**
105→ * Creates an event router that dispatches LiveSelectEvents to
106→ * per-workspace consumers after filtering by workspace.
107→ *
108→ * Pure data structure -- no IO, no side effects beyond calling callbacks.
109→ */
110→export function createEventRouter(): EventRouter {
111→  const workspaceConsumers = new Map<string, Set<EventConsumer>>();
112→  const globalConsumers = new Set<EventConsumer>();
113→
114→  function addConsumer(workspaceId: string, consumer: EventConsumer): () => void {
115→    if (!workspaceConsumers.has(workspaceId)) {
116→      workspaceConsumers.set(workspaceId, new Set());
117→    }
118→    workspaceConsumers.get(workspaceId)!.add(consumer);
119→
120→    return () => {
121→      const consumers = workspaceConsumers.get(workspaceId);
122→      if (consumers) {
123→        consumers.delete(consumer);
124→        if (consumers.size === 0) {
125→          workspaceConsumers.delete(workspaceId);
126→        }
127→      }
128→    };
129→  }
130→
131→  function addGlobalConsumer(consumer: EventConsumer): () => void {
132→    globalConsumers.add(consumer);
133→    return () => {
134→      globalConsumers.delete(consumer);
135→    };
136→  }
137→
138→  function route(event: LiveSelectEvent): void {
139→    // Route to global consumers (no workspace filtering)
140→    for (const consumer of globalConsumers) {
141→      try {
142→        consumer(event);
143→      } catch {
144→        // Consumer errors should not break routing
145→      }
146→    }
147→
148→    // Route to workspace-specific consumers
149→    for (const [workspaceId, consumers] of workspaceConsumers) {
150→      if (matchesWorkspace(event.value, workspaceId)) {
151→        for (const consumer of consumers) {
152→          try {
153→            consumer(event);
154→          } catch {
155→            // Consumer errors should not break routing
156→          }
157→        }
158→      }
159→    }
160→  }
161→
162→  return { addConsumer, addGlobalConsumer, route };
163→}
