/**
 * Walking Skeleton: Graph-Reactive Coordination E2E
 *
 * Traces: US-GRC-01 (Live Feed SSE Bridge)
 *
 * These are the minimum viable E2E paths through the reactive coordination layer.
 * Skeleton 1: Graph write -> SSE event received by workspace admin
 * Skeleton 2: Decision status change -> feed item moves between tiers
 *
 * Together they prove:
 * - LIVE SELECT subscription captures graph changes
 * - Feed SSE Bridge transforms graph events to feed items
 * - SSE Registry delivers events to connected workspace clients
 * - Feed items use the same GovernanceFeedItem contract as the GET endpoint
 * - Tier assignment works correctly for status transitions
 *
 * Driving ports:
 *   GET  /api/workspaces/:workspaceId/feed/stream   (SSE feed stream)
 *   GET  /api/workspaces/:workspaceId/feed           (initial feed state)
 *   SurrealDB direct queries                         (graph write triggers)
 */
import { describe, expect, it, afterEach } from "bun:test";
import {
  setupReactiveSuite,
  createTestUser,
  createTestWorkspace,
  createObservation,
  confirmDecision,
  createDecision,
  openFeedStream,
  getFeedState,
  type FeedStreamController,
} from "./reactive-test-kit";

const getRuntime = setupReactiveSuite("reactive_walking_skeleton");

describe("Walking Skeleton: Workspace admin sees graph changes in real-time feed", () => {
  let feedStream: FeedStreamController | undefined;

  afterEach(() => {
    feedStream?.close();
    feedStream = undefined;
  });

  // ---------------------------------------------------------------------------
  // Walking Skeleton 1: Graph write appears as SSE feed event
  // US-GRC-01: Live Governance Feed via SSE
  // ---------------------------------------------------------------------------
  it("admin sees a new observation in the feed without refreshing the page", async () => {
    const { baseUrl, surreal } = getRuntime();

    // Given a workspace admin has the governance feed open
    const user = await createTestUser(baseUrl, `skeleton-feed-${crypto.randomUUID()}`);
    const { workspaceId } = await createTestWorkspace(surreal, "skeleton-feed");

    feedStream = openFeedStream(baseUrl, workspaceId, user);
    await feedStream.connect();
    expect(feedStream.isConnected()).toBe(true);

    // When the Observer agent creates a warning observation
    await createObservation(surreal, workspaceId, {
      text: "Schema migration missing for new field on task table",
      severity: "warning",
      sourceAgent: "observer_agent",
      category: "engineering",
    });

    // Then within a few seconds, a feed update appears via SSE
    const events = await feedStream.waitForEvents(1, 5000);
    expect(events.length).toBeGreaterThanOrEqual(1);

    // And the feed item describes the observation in business terms
    const feedItems = events.flatMap((e) => e.items);
    const observationItem = feedItems.find((item) =>
      item.title?.includes("Schema migration missing") ||
      item.type === "observation",
    );
    expect(observationItem).toBeDefined();
  }, 30_000);

  // ---------------------------------------------------------------------------
  // Walking Skeleton 2: Decision status change moves item between tiers
  // US-GRC-01: Live Governance Feed via SSE (tier transitions)
  // ---------------------------------------------------------------------------
  it("admin sees a confirmed decision move from blocking to awareness tier", async () => {
    const { baseUrl, surreal } = getRuntime();

    // Given a workspace with a provisional decision in the blocking tier
    const user = await createTestUser(baseUrl, `skeleton-tier-${crypto.randomUUID()}`);
    const { workspaceId } = await createTestWorkspace(surreal, "skeleton-tier");

    const { decisionId } = await createDecision(surreal, workspaceId, {
      summary: "Standardize on tRPC for all APIs",
      status: "provisional",
    });

    // And the admin has the governance feed open
    feedStream = openFeedStream(baseUrl, workspaceId, user);
    await feedStream.connect();
    expect(feedStream.isConnected()).toBe(true);

    // When the chat agent confirms the decision
    await confirmDecision(surreal, decisionId);

    // Then within a few seconds, a feed update reflects the tier change
    const events = await feedStream.waitForEvents(1, 5000);
    expect(events.length).toBeGreaterThanOrEqual(1);

    // And the update either removes the decision from blocking or adds an awareness item
    const allItems = events.flatMap((e) => e.items);
    const allRemovals = events.flatMap((e) => e.removals ?? []);
    const hasTransition =
      allItems.some((item) =>
        item.title?.includes("tRPC") || item.title?.includes("confirmed"),
      ) || allRemovals.length > 0;
    expect(hasTransition).toBe(true);
  }, 30_000);
});

/**
 * Milestone 1: Live Governance Feed via SSE (US-GRC-01)
 *
 * Traces: US-GRC-01 acceptance criteria
 *
 * Tests the LIVE SELECT -> Feed SSE Bridge -> SSE delivery pipeline.
 * Scenarios cover: connection lifecycle, feed item delivery, tier assignment,
 * reconnection with delta sync, keep-alive, and high-volume batching.
 *
 * Driving ports:
 *   GET  /api/workspaces/:workspaceId/feed/stream   (SSE feed stream)
 *   GET  /api/workspaces/:workspaceId/feed           (initial feed state)
 *   SurrealDB direct queries                         (graph write triggers)
 */
import { describe, expect, it, afterEach } from "bun:test";
import {
  setupReactiveSuite,
  createTestUser,
  createTestWorkspace,
  createObservation,
  createDecision,
  createTask,
  confirmDecision,
  blockTask,
  openFeedStream,
  getFeedState,
  fetchRaw,
  type FeedStreamController,
} from "./reactive-test-kit";

const getRuntime = setupReactiveSuite("feed_sse_bridge");

describe("US-GRC-01: Live Governance Feed via SSE", () => {
  // ---------------------------------------------------------------------------
  // AC: SSE endpoint established on feed page load
  // ---------------------------------------------------------------------------
  it("feed establishes SSE connection for workspace", async () => {
    const { baseUrl, surreal } = getRuntime();
    const user = await createTestUser(baseUrl, `sse-connect-${crypto.randomUUID()}`);
    const { workspaceId } = await createTestWorkspace(surreal, "sse-connect");

    const feedStream = openFeedStream(baseUrl, workspaceId, user);
    try {
      await feedStream.connect();
      expect(feedStream.isConnected()).toBe(true);
    } finally {
      feedStream.close();
    }
  }, 15_000);

  // ---------------------------------------------------------------------------
  // AC: New items appear in the correct tier within 2 seconds
  // ---------------------------------------------------------------------------
  it("new observation appears in feed within 2 seconds of graph write", async () => {
    const { baseUrl, surreal } = getRuntime();
    const user = await createTestUser(baseUrl, `latency-${crypto.randomUUID()}`);
    const { workspaceId } = await createTestWorkspace(surreal, "latency");

    const feedStream = openFeedStream(baseUrl, workspaceId, user);
    try {
      await feedStream.connect();

      const writeTime = Date.now();
      await createObservation(surreal, workspaceId, {
        text: "Task T-47 implementation contradicts confirmed decision D-99",
        severity: "conflict",
        sourceAgent: "observer_agent",
      });

      const events = await feedStream.waitForEvents(1, 3000);
      const receiveTime = Date.now();

      expect(events.length).toBeGreaterThanOrEqual(1);
      expect(receiveTime - writeTime).toBeLessThan(2000);
    } finally {
      feedStream.close();
    }
  }, 15_000);

  // ---------------------------------------------------------------------------
  // AC: Feed items use same GovernanceFeedItem contract as GET endpoint
  // ---------------------------------------------------------------------------
  it("SSE feed items match the same contract as the initial feed load", async () => {
    const { baseUrl, surreal } = getRuntime();
    const user = await createTestUser(baseUrl, `contract-${crypto.randomUUID()}`);
    const { workspaceId } = await createTestWorkspace(surreal, "contract");

    const initialFeed = await getFeedState(baseUrl, workspaceId, user);

    const feedStream = openFeedStream(baseUrl, workspaceId, user);
    try {
      await feedStream.connect();

      await createObservation(surreal, workspaceId, {
        text: "Unused API endpoint detected in billing service",
        severity: "warning",
        sourceAgent: "observer_agent",
      });

      const events = await feedStream.waitForEvents(1, 5000);
      expect(events.length).toBeGreaterThanOrEqual(1);

      const sseItem = events[0].items[0];
      expect(sseItem).toHaveProperty("id");
      expect(sseItem).toHaveProperty("type");
      expect(sseItem).toHaveProperty("tier");
      expect(sseItem).toHaveProperty("title");
    } finally {
      feedStream.close();
    }
  }, 15_000);

  // ---------------------------------------------------------------------------
  // AC: Decision confirmation moves item between tiers
  // ---------------------------------------------------------------------------
  it("confirming a decision removes it from blocking tier and adds awareness item", async () => {
    const { baseUrl, surreal } = getRuntime();
    const user = await createTestUser(baseUrl, `tier-move-${crypto.randomUUID()}`);
    const { workspaceId } = await createTestWorkspace(surreal, "tier-move");

    const { decisionId } = await createDecision(surreal, workspaceId, {
      summary: "Use event sourcing for audit trail",
      status: "provisional",
    });

    const feedStream = openFeedStream(baseUrl, workspaceId, user);
    try {
      await feedStream.connect();

      await confirmDecision(surreal, decisionId);

      const events = await feedStream.waitForEvents(1, 5000);
      expect(events.length).toBeGreaterThanOrEqual(1);

      const allItems = events.flatMap((e) => e.items);
      const allRemovals = events.flatMap((e) => e.removals ?? []);
      const confirmedItem = allItems.find(
        (item) => item.title?.includes("event sourcing") || item.title?.includes("confirmed"),
      );
      const hasRemoval = allRemovals.some((id) => id.includes(decisionId));

      expect(confirmedItem !== undefined || hasRemoval).toBe(true);
    } finally {
      feedStream.close();
    }
  }, 15_000);

  // ---------------------------------------------------------------------------
  // AC: Task blocked appears in correct tier
  // ---------------------------------------------------------------------------
  it("blocking a task surfaces it in the review tier", async () => {
    const { baseUrl, surreal } = getRuntime();
    const user = await createTestUser(baseUrl, `task-block-${crypto.randomUUID()}`);
    const { workspaceId } = await createTestWorkspace(surreal, "task-block");

    const { taskId } = await createTask(surreal, workspaceId, {
      title: "Implement user authentication flow",
      status: "in_progress",
    });

    const feedStream = openFeedStream(baseUrl, workspaceId, user);
    try {
      await feedStream.connect();

      await blockTask(surreal, taskId);

      const events = await feedStream.waitForEvents(1, 5000);
      expect(events.length).toBeGreaterThanOrEqual(1);

      const allItems = events.flatMap((e) => e.items);
      const blockedItem = allItems.find(
        (item) => item.title?.includes("authentication") || item.title?.includes("blocked"),
      );
      expect(blockedItem).toBeDefined();
    } finally {
      feedStream.close();
    }
  }, 15_000);

  // ---------------------------------------------------------------------------
  // AC: SSE keep-alive maintains connection
  // ---------------------------------------------------------------------------
  it("SSE connection sends keep-alive and stays open during idle periods", async () => {
    const { baseUrl, surreal } = getRuntime();
    const user = await createTestUser(baseUrl, `keepalive-${crypto.randomUUID()}`);
    const { workspaceId } = await createTestWorkspace(surreal, "keepalive");

    const feedStream = openFeedStream(baseUrl, workspaceId, user);
    try {
      await feedStream.connect();

      await new Promise((resolve) => setTimeout(resolve, 20_000));

      expect(feedStream.isConnected()).toBe(true);

      const rawEvents = feedStream.getRawEvents();
      // Keep-alive comments or heartbeats should exist
      // The connection itself not timing out is the primary assertion
    } finally {
      feedStream.close();
    }
  }, 30_000);

  // ---------------------------------------------------------------------------
  // AC: On reconnection, missed events are replayed (delta sync)
  // ---------------------------------------------------------------------------
  it("missed events are delivered after brief reconnection", async () => {
    const { baseUrl, surreal } = getRuntime();
    const user = await createTestUser(baseUrl, `reconnect-${crypto.randomUUID()}`);
    const { workspaceId } = await createTestWorkspace(surreal, "reconnect");

    let feedStream = openFeedStream(baseUrl, workspaceId, user);
    try {
      await feedStream.connect();

      await createObservation(surreal, workspaceId, {
        text: "Initial observation before disconnect",
        severity: "info",
        sourceAgent: "observer_agent",
      });
      await feedStream.waitForEvents(1, 5000);

      const lastEventId = feedStream.getLastEventId();
      feedStream.close();

      await createObservation(surreal, workspaceId, {
        text: "Observation created during disconnect",
        severity: "warning",
        sourceAgent: "observer_agent",
      });
      await createDecision(surreal, workspaceId, {
        summary: "Decided during disconnect: Use PostgreSQL for analytics",
        status: "provisional",
      });

      await new Promise((resolve) => setTimeout(resolve, 1000));

      feedStream = openFeedStream(baseUrl, workspaceId, user, { lastEventId });
      await feedStream.connect();

      const events = await feedStream.waitForEvents(1, 5000);
      expect(events.length).toBeGreaterThanOrEqual(1);

      const feedState = await getFeedState(baseUrl, workspaceId, user);
      expect(feedState).toBeDefined();
    } finally {
      feedStream.close();
    }
  }, 30_000);

  // ---------------------------------------------------------------------------
  // AC: No duplicate feed items after reconnection
  // ---------------------------------------------------------------------------
  it("feed items are not duplicated after reconnection", async () => {
    const { baseUrl, surreal } = getRuntime();
    const user = await createTestUser(baseUrl, `dedup-${crypto.randomUUID()}`);
    const { workspaceId } = await createTestWorkspace(surreal, "dedup");

    const { observationId } = await createObservation(surreal, workspaceId, {
      text: "Unique observation for dedup test",
      severity: "info",
      sourceAgent: "observer_agent",
    });

    let feedStream = openFeedStream(baseUrl, workspaceId, user);
    try {
      await feedStream.connect();
      await feedStream.waitForEvents(1, 3000);
      feedStream.close();

      feedStream = openFeedStream(baseUrl, workspaceId, user);
      await feedStream.connect();
      await feedStream.waitForEvents(1, 3000);

      const feedState = await getFeedState(baseUrl, workspaceId, user);
      const items = (feedState as { items?: Array<{ id: string }> }).items ?? [];
      const matchingItems = items.filter((item) => item.id?.includes(observationId));
      expect(matchingItems.length).toBeLessThanOrEqual(1);
    } finally {
      feedStream.close();
    }
  }, 30_000);

  // ---------------------------------------------------------------------------
  // AC: High-volume event bursts are batched (500ms window)
  // ---------------------------------------------------------------------------
  it("rapid graph changes are batched into fewer SSE events", async () => {
    const { baseUrl, surreal } = getRuntime();
    const user = await createTestUser(baseUrl, `batch-${crypto.randomUUID()}`);
    const { workspaceId } = await createTestWorkspace(surreal, "batch");

    const feedStream = openFeedStream(baseUrl, workspaceId, user);
    try {
      await feedStream.connect();

      const createPromises = Array.from({ length: 10 }, (_, i) =>
        createObservation(surreal, workspaceId, {
          text: `Batch observation ${i + 1}`,
          severity: "info",
          sourceAgent: "observer_agent",
        }),
      );
      await Promise.all(createPromises);

      await new Promise((resolve) => setTimeout(resolve, 2000));
      const events = feedStream.getEvents();

      expect(events.length).toBeLessThan(10);
      expect(events.length).toBeGreaterThanOrEqual(1);

      const totalItems = events.reduce((sum, e) => sum + e.items.length, 0);
      expect(totalItems).toBeGreaterThanOrEqual(1);
    } finally {
      feedStream.close();
    }
  }, 15_000);
});

/**
 * Live Select Manager: Acceptance Tests
 *
 * Step: 01-03 (graph-reactive-coordination)
 *
 * Proves:
 * - LIVE SELECT subscriptions are created for governance tables
 * - Events are received when records are created/updated in subscribed tables
 * - Events are filtered application-side by workspace
 * - Subscription start/stop is logged for observability
 *
 * Driving ports:
 *   SurrealDB direct queries (graph writes trigger LIVE SELECT)
 *   LiveSelectManager.start() / stop() (subscription lifecycle)
 */
import { describe, expect, it, afterEach } from "bun:test";
import { RecordId, Table } from "surrealdb";
import {
  setupReactiveSuite,
  createTestWorkspace,
} from "./reactive-test-kit";
import {
  createLiveSelectManager,
  type LiveSelectEvent,
  type LiveSelectManager,
} from "../../../app/src/server/reactive/live-select-manager";

const getRuntime = setupReactiveSuite("live_select_manager");

describe("Live Select Manager: subscribe to governance tables and route events", () => {
  // ---------------------------------------------------------------------------
  // AC: Subscriptions created per workspace for governance tables
  // AC: Events filtered application-side by workspace
  // ---------------------------------------------------------------------------
  it("receives events for the correct workspace when a decision is created", async () => {
    const { surreal } = getRuntime();

    const { workspaceId: targetWorkspaceId } = await createTestWorkspace(surreal, "lsm-target");
    const { workspaceId: otherWorkspaceId } = await createTestWorkspace(surreal, "lsm-other");

    const receivedEvents: LiveSelectEvent[] = [];
    const handleEvent = (event: LiveSelectEvent) => {
      receivedEvents.push(event);
    };

    const manager = createLiveSelectManager({ surreal });
    try {
      manager.onEvent(targetWorkspaceId, handleEvent);
      await manager.start();

      await new Promise((resolve) => setTimeout(resolve, 500));

      const targetDecisionId = `dec-${crypto.randomUUID()}`;
      await surreal.query(`CREATE $rec CONTENT $content;`, {
        rec: new RecordId("decision", targetDecisionId),
        content: {
          summary: "Use tRPC for all APIs",
          status: "provisional",
          workspace: new RecordId("workspace", targetWorkspaceId),
          created_at: new Date(),
          updated_at: new Date(),
        },
      });

      const otherDecisionId = `dec-${crypto.randomUUID()}`;
      await surreal.query(`CREATE $rec CONTENT $content;`, {
        rec: new RecordId("decision", otherDecisionId),
        content: {
          summary: "Use REST for all APIs",
          status: "provisional",
          workspace: new RecordId("workspace", otherWorkspaceId),
          created_at: new Date(),
          updated_at: new Date(),
        },
      });

      await new Promise((resolve) => setTimeout(resolve, 2000));

      expect(receivedEvents.length).toBeGreaterThanOrEqual(1);

      const targetEvents = receivedEvents.filter(
        (e) => e.table === "decision" && e.action === "CREATE",
      );
      expect(targetEvents.length).toBe(1);
      expect(targetEvents[0].recordId).toContain(targetDecisionId);
    } finally {
      await manager.stop();
    }
  }, 15_000);

  // ---------------------------------------------------------------------------
  // AC: Subscriptions for all governance tables (not just decision)
  // ---------------------------------------------------------------------------
  it("receives events from multiple governance tables", async () => {
    const { surreal } = getRuntime();

    const { workspaceId } = await createTestWorkspace(surreal, "lsm-multi");

    const receivedEvents: LiveSelectEvent[] = [];
    const manager = createLiveSelectManager({ surreal });
    try {
      manager.onEvent(workspaceId, (event) => receivedEvents.push(event));
      await manager.start();

      await new Promise((resolve) => setTimeout(resolve, 500));

      const workspaceRecord = new RecordId("workspace", workspaceId);

      await surreal.query(`CREATE $rec CONTENT $content;`, {
        rec: new RecordId("task", `task-${crypto.randomUUID()}`),
        content: {
          title: "Implement rate limiting",
          status: "open",
          workspace: workspaceRecord,
          created_at: new Date(),
          updated_at: new Date(),
        },
      });

      await surreal.query(`CREATE $rec CONTENT $content;`, {
        rec: new RecordId("observation", `obs-${crypto.randomUUID()}`),
        content: {
          text: "Schema drift detected",
          severity: "warning",
          status: "open",
          source_agent: "observer_agent",
          workspace: workspaceRecord,
          created_at: new Date(),
        },
      });

      await new Promise((resolve) => setTimeout(resolve, 2000));

      const tables = new Set(receivedEvents.map((e) => e.table));
      expect(tables.has("task")).toBe(true);
      expect(tables.has("observation")).toBe(true);
    } finally {
      await manager.stop();
    }
  }, 15_000);

  // ---------------------------------------------------------------------------
  // AC: Subscription start/stop logged for observability
  // ---------------------------------------------------------------------------
  it("logs subscription lifecycle for observability", async () => {
    const { surreal } = getRuntime();

    const logEntries: Array<{ level: string; message: string }> = [];
    const testLogger = {
      info: (message: string) => logEntries.push({ level: "info", message }),
      warn: (message: string) => logEntries.push({ level: "warn", message }),
      error: (message: string) => logEntries.push({ level: "error", message }),
    };

    const manager = createLiveSelectManager({ surreal, logger: testLogger });
    try {
      await manager.start();

      await new Promise((resolve) => setTimeout(resolve, 500));

      const startLogs = logEntries.filter(
        (e) => e.level === "info" && e.message.includes("subscribed"),
      );
      expect(startLogs.length).toBeGreaterThanOrEqual(1);

      await manager.stop();

      const stopLogs = logEntries.filter(
        (e) => e.level === "info" && e.message.includes("stopped"),
      );
      expect(stopLogs.length).toBeGreaterThanOrEqual(1);
    } finally {
      // stop() is idempotent -- safe to call again if already stopped
      await manager.stop().catch(() => {});
    }
  }, 15_000);
});

